import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Header from './components/Header';
import Home from './pages/Home';
import Catalog from './pages/Catalog';
import About from './pages/About';
import Register from './pages/Register';
import Cart from './components/Cart';
import './App.css';
import Vacancy from './pages/Vacancy'; 

function App() {
    const [cartItems, setCartItems] = useState([]);
    const [showCart, setShowCart] = useState(false);

    const addToCart = (product) => { /* твой код */ };
    const removeFromCart = (productId) => { /* твой код */ };
    const updateQuantity = (productId, newQuantity) => { /* твой код */ };

    const cartTotal = cartItems.reduce((sum, item) => sum + item.price * item.quantity, 0);
    const cartCount = cartItems.reduce((sum, item) => sum + item.quantity, 0);

    return (
        <Router>
            <div className="App">
                <Header
                    cartCount={cartCount}
                    onCartClick={() => setShowCart(true)}
                />

                {showCart && (
                    <div className="cart-overlay" onClick={() => setShowCart(false)}>
                        <div className="cart-modal" onClick={e => e.stopPropagation()}>
                            <Cart
                                items={cartItems}
                                onUpdateQuantity={updateQuantity}
                                onRemove={removeFromCart}
                                total={cartTotal}
                                onClose={() => setShowCart(false)}
                            />
                        </div>
                    </div>
                )}

                <main>
                    <Routes>
                        <Route path="/" element={<Home />} />
                        <Route
                            path="/catalog"
                            element={<Catalog addToCart={addToCart} />}
                        />
                        <Route path="/about" element={<About />} />
                        <Route path="/register" element={<Register />} />
                        <Route path="/vacancy" element={<Vacancy />} />
                    </Routes>
                </main>

                <footer className="footer">
                    <div className="footer-content">
                        <div className="footer-section">
                            {/* Можно поменять на Семисвинофф, если это он :) */}
                            <h3>Семисвинофф</h3> 
                            <p>Доставка продуктов на дом</p>
                        </div>
                        <div className="footer-section">
                            <h4>Контакты</h4>
                            <p>📞 +7 (800) 123-45-67</p>
                            <p>📧 info@semisvinoff.ru</p>
                        </div>
                        <div className="footer-section">
                            <h4>Время работы</h4>
                            <p>Ежедневно с 8:00 до 23:00</p>
                        </div>
                    </div>
                </footer>
            </div>
        </Router>
    );
}

export default App;
